    # curl -X POST -H "Content-Type: application/json" -d '{"email_text": "Meeting tomorrow at 3 PM regarding the project."}' http://127.0.0.1:5000/predict_spam
    app.run(debug=True) # debug=True reloads the server on code changes and provides a debugger